mapper.select:
SELECT T1. ID, T1.COMPANY_ID, T1.COMPANY_NAME, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.TRUST_ID, T1.SHIPVOYAGE_ID, T1.SHIPVOYAGE_ITEM_ID, T1.HATCH, T3.SHIP_NAME, T3.SHIP_NAME SHIPVOYAGE_LABEL, T1.HATCH, T1.PLAN_NO, T1.PLAN_TYPE, T1.PROCESS_CODE, T1.PROCESS_NAME, T1.WORK_CONTENT, T1.DEPT_ID, T1.DEPT_NAME, T1.QUANTITY_PLAN, T1.TON_PLAN, T1.START_TIME_PLAN, T1.END_TIME_PLAN, T1.START_WORK_TIME, T1.END_WORK_TIME, T1.REMARK, T1.STATUS, M1.NM AS STATUS_LABEL, T3.SCN, T1.BERTH_ID, T1.BERTH_NAME, T1.FRONT_TALLY_BY, T1.FRONT_TALLY_BY_NAME, T1.BACK_TALLY_BY, T1.BACK_TALLY_BY_NAME, T1.DISPATCH_BY, T1.DISPATCH_BY_NAME, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.EXAMINE_BY, T1.EXAMINE_BY_NAME, T1.EXAMINE_TIME, T1.EQUIPMENT_NAMES_FRONT, T1.EQUIPMENT_NAMES_BACK, T1.EQUIPMENT_NAMES_ASSIST, T1.EQUIPMENT_NAMES_RESHIPMENT, T1.MASS_NAMES_SOURCE, T1.MASS_NAMES_TARGET, T1.RESHIPMENT_TYPE_CODE, M2.NM AS RESHIPMENT_TYPE_Label, T1.BUS_CARGO_INFO_ID, T1.CARGO_CATEGORY_CODE, T1.CARGO_CATEGORY_NAME, T2.NUM AS LABOR_NUM, T7.SHIP_NAME, T4.VOYAGE, 5 AS HATCH_NUM, T4.LOAD_UNLOAD, T7.CARGO_NAME, T7.CARGO_OWNER_NAME, T7.CARGO_INFO_NO, T7.TRUST_INFO_NO, T8.TARGET_CD, T8.SOURCE_CD, T8.IS_DIRECT_ACCESS, T9.WORK_STATUS workStatus, TDS.ID AS secondaryId, T10.STATUS confirmStatus FROM T_PRD_WORK_PLAN T1 LEFT JOIN T_PRD_DISPATCH T2 ON T1. ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' LEFT JOIN m_constants M1 ON T1.STATUS = M1.CD AND M1.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN m_constants M2 ON T1.RESHIPMENT_TYPE_CODE = M2.CD AND M2.TYPE_CD = 'RESHIPMENT_TYPE' LEFT JOIN T_DIS_SHIPVOYAGE T3 ON T1.SHIPVOYAGE_ID = T3. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T4 ON T4. ID = T1.SHIPVOYAGE_ITEM_ID LEFT JOIN T_PRD_DISPATCH_SECONDARY TDS ON TDS.WORK_PLAN_ID = T1.ID AND TDS.EQUIPMENT_NO = #{macName} LEFT JOIN M_WORK_PROCESS T8 ON T1. PROCESS_CODE = T8.PROCESS_CD LEFT JOIN ( SELECT WORK_STATUS, PLAN_ID, ROW_NUMBER() OVER (PARTITION BY PLAN_ID ORDER BY CREATE_TIME DESC) AS rn FROM T_BUS_RESERVATION_POUND WHERE TRUCK_NO = #{macName} ) T9 ON T9.PLAN_ID = T1.ID AND T9.rn = 1 LEFT JOIN ( SELECT STATUS, PLAN_ID, ROW_NUMBER() OVER (PARTITION BY PLAN_ID ORDER BY CREATE_TIME DESC) AS rn FROM T_BUS_RESERVATION_CONFIRM WHERE TRUCK_NO = #{macName} AND STATUS != '2' ) T10 ON T10.PLAN_ID = T1.ID AND T9.rn = 1 LEFT JOIN ( SELECT A .TRUST_ID, T6.SHIP_NAME, LISTAGG (TO_CHAR(T6.CARGO_INFO_NO), ',') WITHIN GROUP (ORDER BY T6.CARGO_INFO_NO) CARGO_INFO_NO, LISTAGG (TO_CHAR(T6.CARGO_NAME), ',') WITHIN GROUP (ORDER BY T6.TRUST_ID) CARGO_NAME, LISTAGG ( TO_CHAR (T6.CARGO_OWNER_NAME), ',' ) WITHIN GROUP (ORDER BY T6.TRUST_ID) CARGO_OWNER_NAME, LISTAGG ( TO_CHAR (A.BUSINESS_NO), ',' ) WITHIN GROUP (ORDER BY A.TRUST_ID) TRUST_INFO_NO FROM T_BUS_CARGO_INFO T6, T_BUS_TRUST_CARGO A, T_BUS_TRUST T5 WHERE A .CARGO_INFO_ID = T6. ID AND T5. ID = A .TRUST_ID GROUP BY A .TRUST_ID, T6.SHIP_NAME ) T7 ON T7.TRUST_ID = T1.TRUST_ID where T1.CLASS_CODE = #{classCode} AND WORK_DATE = TO_DATE(#{workDateString},'YYYY-MM-DD') and T1.STATUS = 20 AND T1.PLAN_TYPE = 1
AND T3.SHIP_NAME LIKE #{shipNameVoyage_like}
AND T4.VOYAGE LIKE #{voyage_like}
AND T7.TRUST_INFO_NO LIKE #{businessNo_like}
AND T7.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
AND T8.IS_DIRECT_ACCESS = 0 AND T8.PROCESS_CD IN ('1025','1026')
AND T1.ID IN (SELECT WORK_PLAN_ID FROM T_PRD_DISPATCH_SECONDARY WHERE EQUIPMENT_NO = #{macName})

select LISTAGG ( '''' || TO_CHAR(BUSINESS_NO) || '''', ',') WITHIN GROUP (ORDER BY BUSINESS_NO) "businessNo"  from T_BUS_TRUST_CARGO A1 LEFT JOIN T_BUS_TRUST A2  ON A1.TRUST_ID = A2.ID
 WHERE A1.TRUST_ID = #{trustId,jdbcType=VARCHAR}

    AND A1.CARGO_INFO_ID = #{cargoInfoId}

SELECT LISTAGG ( '''' || TO_CHAR(BUSINESS_NO) || '''', ',') WITHIN GROUP (ORDER BY BUSINESS_NO) "businessNo" FROM T_BUS_TRUST T1 LEFT JOIN T_BUS_TRUST_CARGO T2 ON T1. ID = T2.TRUST_ID WHERE T2.CARGO_INFO_ID IN ( SELECT A1.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO A1 WHERE A1.TRUST_ID = #{trustId,jdbcType=VARCHAR}
AND A1.CARGO_INFO_ID = #{cargoInfoId}
) AND T1.TYPE IN
#{item,jdbcType=VARCHAR}

SELECT A1.BUSINESS_NO "businessNo",A2.PORT_CODE "portCode" from T_BUS_TRUST_CARGO A1 LEFT JOIN T_BUS_TRUST A2 ON A1.TRUST_ID = A2.ID
WHERE A1.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT} AND A2.TYPE IN

    #{item,jdbcType=VARCHAR}

SELECT
    count(A1.ID)
FROM
    T_YARD_TALLY A1 LEFT JOIN T_PRD_WORK_PLAN A2 ON A1.PLAN_ID = A2.ID
WHERE
    A2.TRUST_ID = #{trustId,jdbcType=BIGINT}
AND A1.PROCESS_CODE = #{processCode,jdbcType=VARCHAR}
AND A1.RELATION_ID IS NULL AND DEL_FLAG = 0
AND A1.TRANSPORT_EQUIPMENT_ID = #{transportEquipmentId,jdbcType=BIGINT}

mapper.insert:
INSERT INTO T_YARD_TALLY_ITEM( ID, TALLY_ID, CARGO_INFO_ID, IN_OUT_ID, CARGO_CODE, CARGO_NAME, QUANTITY, TON, STOREHOUSE_ID, STOREHOUSE_NAME, LOCATION_ID, LOCATION_NO, STACK_POSITION_ID, STACK_POSITION_NAME, CABIN_NO, TRUST_CARGO_INFO_ID, REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME ) (
select #{item.id,jdbcType=BIGINT}, #{item.tallyId,jdbcType=BIGINT}, #{item.cargoInfoId,jdbcType=BIGINT}, #{item.inOutId,jdbcType=BIGINT}, #{item.cargoCode,jdbcType=VARCHAR}, #{item.cargoName,jdbcType=VARCHAR}, #{item.quantity,jdbcType=DOUBLE}, #{item.ton,jdbcType=DOUBLE}, #{item.storehouseId,jdbcType=BIGINT}, #{item.storehouseName,jdbcType=VARCHAR}, #{item.locationId,jdbcType=BIGINT}, #{item.locationNo,jdbcType=VARCHAR}, #{item.stackPositionId,jdbcType=BIGINT}, #{item.stackPositionName,jdbcType=VARCHAR}, #{item.cabinNo,jdbcType=VARCHAR}, #{item.trustCargoInfoId,jdbcType=BIGINT}, #{item.remark,jdbcType=VARCHAR}, #{item.loginUserId,jdbcType=VARCHAR}, #{item.loginUserName,jdbcType=VARCHAR}, #{item.now} from dual
)

mapper.select:
SELECT A1.ID, A1.PLAN_ID, A1.RELATION_ID, A1.SHIPVOYAGE_ID, A1.OPERATORS_ID, A1.OPERATORS_NAME, A1.TRANSPORT_OPERATORS_ID, A1.TRANSPORT_OPERATORS_NAME, A1.PROCESS_CODE, A1.PROCESS_NAME, A1.EQUIPMENT_ID, A1.EQUIPMENT_NO, A1.TRANSPORT_EQUIPMENT_ID, A1.TRANSPORT_EQUIPMENT_NO, A1.DEPT_ID, A1.DEPT_NAME, A1.QUANTITY, A1.TON, A1.CREATE_BY, A1.CREATE_BY_NAME, A1.CREATE_TIME FROM T_YARD_TALLY A1 LEFT JOIN T_PRD_WORK_PLAN A2 ON A1.PLAN_ID = A2.ID WHERE A2.TRUST_ID = #{trustId,jdbcType=BIGINT} AND A1.DEL_FLAG = 0 AND A1.REMARK IS NULL
AND A1.TRANSPORT_EQUIPMENT_NO = #{macName}
ORDER BY A1.CREATE_TIME DESC

SELECT A2.ID, A2.TALLY_ID, A1.EQUIPMENT_NO, A1.EQUIPMENT_ID, A1.OPERATORS_ID, A1.OPERATORS_NAME, A1.PROCESS_CODE, A1.PROCESS_NAME, A2.CABIN_NO, A1.TRANSPORT_EQUIPMENT_ID, A1.TRANSPORT_EQUIPMENT_NO, A2.QUANTITY, A2.TON, A2.CARGO_CODE, A4.CARGO_INFO_NO || '/'|| A4.CARGO_OWNER_NAME || '/' || A2.CARGO_NAME CARGO_NAME, A2.STOREHOUSE_NAME, A2.STOREHOUSE_ID, A2.LOCATION_ID, A2.LOCATION_NO, A2.STACK_POSITION_ID, A2.STACK_POSITION_NAME, A2.CREATE_BY, A2.CREATE_BY_NAME, A2.CREATE_TIME, A2.CARGO_INFO_ID, A5.CLASS_CODE, A5.CLASS_NAME, A5.WORK_DATE, A3.CREATE_TIME CREATE_TIME_H ,A3.CREATE_BY_NAME CREATE_BY_NAME_H, CASE WHEN A3.CREATE_BY_NAME IS NULL THEN '待理货' ELSE '已理货' END TALLY_STATUS_NAME FROM T_YARD_TALLY a1 LEFT JOIN T_YARD_TALLY_ITEM a2 on A2.TALLY_ID = A1.id LEFT JOIN T_YARD_TALLY a3 ON A1. ID = a3.RELATION_ID AND A3.DEL_FLAG = 0 LEFT JOIN T_BUS_CARGO_INFO a4 ON A2. CARGO_INFO_ID = a4.ID LEFT JOIN T_PRD_WORK_PLAN a5 on a5.ID = A1.PLAN_ID WHERE A1.REMARK IS NULL AND A1.DEL_FLAG = 0
AND A5.TRUST_ID = #{trustId,jdbcType=BIGINT}
AND A1.PLAN_ID = #{planId,jdbcType=BIGINT}
AND A5.CLASS_CODE = #{classCode,jdbcType=VARCHAR}
and TO_CHAR(a5.WORK_DATE ,'yyyy-MM-dd') = #{workDate,jdbcType=VARCHAR}
AND A1.PROCESS_CODE = #{processCode,jdbcType=VARCHAR}
AND A1.TRANSPORT_EQUIPMENT_NO like #{transportEquipmentNo_like,jdbcType=VARCHAR}
AND A1.EQUIPMENT_NO like #{equipmentNo_like,jdbcType=VARCHAR}
AND A2.CREATE_BY_NAME like #{createName_like,jdbcType=VARCHAR}
AND A2.STACK_POSITION_NAME like #{stackPosition_like,jdbcType=VARCHAR}
AND A2.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}
AND A4.CARGO_INFO_NO = #{cargoInfoNo,jdbcType=VARCHAR}
and to_char(A2.CREATE_TIME,'YYYY-MM-DD HH24:MI:SS') >= #{startTime}
and to_char(A2.CREATE_TIME,'YYYY-MM-DD HH24:MI:SS') <= #{endTime}
ORDER BY A2.CREATE_TIME DESC

SELECT
COUNT (DISTINCT(A1. ID)) "mahcineCount",
NVL( sum(A2.QUANTITY),0) "treeCount",
NVL( sum(A2.TON),0) "tonCount"
FROM
T_YARD_TALLY a1
LEFT JOIN T_YARD_TALLY_ITEM a2 on A2.TALLY_ID = A1.id
LEFT JOIN T_BUS_CARGO_INFO a4 ON A2. CARGO_INFO_ID = a4.ID
LEFT JOIN T_PRD_WORK_PLAN a5 on a5.ID = A1.PLAN_ID
WHERE A5.TRUST_ID = #{trustId,jdbcType=BIGINT} AND A1.DEL_FLAG = 0 AND A1.REMARK IS NULL

    AND A5.CLASS_CODE = #{classCode,jdbcType=VARCHAR}


    and TO_CHAR(a5.WORK_DATE ,'yyyy-MM-dd') = #{workDate,jdbcType=VARCHAR}


    AND A1.PROCESS_CODE = #{processCode,jdbcType=VARCHAR}



    AND  A1.TRANSPORT_EQUIPMENT_NO like  #{transportEquipmentNo_like,jdbcType=VARCHAR}



    AND  A1.EQUIPMENT_NO like  #{equipmentNo_like,jdbcType=VARCHAR}




    AND  A2.CREATE_BY_NAME like  #{createName_like,jdbcType=VARCHAR}



    AND  A2.STACK_POSITION_NAME like  #{stackPosition_like,jdbcType=VARCHAR}


    AND  A2.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}


    AND  A4.CARGO_INFO_NO = #{cargoInfoNo,jdbcType=VARCHAR}


    and to_char(A2.CREATE_TIME,'YYYY-MM-DD HH24:MI:SS') >= #{startTime}


    and to_char(A2.CREATE_TIME,'YYYY-MM-DD HH24:MI:SS') <= #{endTime}

ORDER BY A2.CREATE_TIME DESC

SELECT A1. ID "inOutId", A1.CARGO_INFO_ID, A1.STOREHOUSE_ID, A1.STOREHOUSE_NAME, A1.REGION_ID LOCATION_ID, A1.REGION_NAME LOCATION_NO, A1.MASS_ID STACK_POSITION_ID, A1.MASS_NAME STACK_POSITION_NAME, A3.CARGO_CODE, A3.CARGO_NAME, A3.CARGO_INFO_NO, A1.QUANTITY quantitySurplus, A1.TON tonSurplus FROM T_PRD_PORT_STORAGE A1 LEFT JOIN T_BUS_CARGO_INFO a3 on a3.ID = a1.CARGO_INFO_ID LEFT JOIN M_STORAGE_YARD st on st.ID = A1.REGION_ID WHERE
CARGO_INFO_ID IN ${trustIds}
AND A1.MASS_NAME like #{stackPosition_like,jdbcType=VARCHAR}
AND A1.CARGO_INFO_ID like #{cargoInfoId}
AND (st.IS_FRONTIER != '1' OR st.IS_FRONTIER IS NULL)
AND st.IS_FRONTIER = '1'

SELECT A1.ID, A1.NUM, A1.CARGO_INFO_ID, A1.COIL_NUM, A1.TON, A1.COIL_SIZE1, A1.COIL_SIZE2, A1.STATUS, A1.RECEIVE_ADDRESS, LISTAGG (TO_CHAR (A3.CREATE_BY_NAME), ',') WITHIN GROUP (ORDER BY A1.ID) CREATE_BY_NAME, LISTAGG (TO_CHAR(A3.CREATE_TIME,'yyyy-mm-dd hh24:mi'), ',') WITHIN GROUP (ORDER BY A1.ID) AS CREATE_TIMES FROM T_BUS_CARGO_INFO_COILNUM A1 LEFT JOIN T_BUS_TALLY_COILNUM A2 ON A1. ID = A2.COIL_ID LEFT JOIN T_YARD_TALLY A3 ON A3. ID = A2.TALLY_ID WHERE CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}
AND A1.NUM like #{num_like}
AND A1.COIL_NUM like #{coilNum_like}
AND A1.STATUS = #{status}
GROUP BY A1. ID, A1.NUM, A1.CARGO_INFO_ID, A1.COIL_NUM, A1.TON, A1.COIL_SIZE1, A1.COIL_SIZE2, A1.STATUS, A1.RECEIVE_ADDRESS ORDER BY A1.NUM, A1.STATUS,A1.COIL_NUM

