UPDATE T_YARD_TALLY
EQUIPMENT_ID = #{equipmentId,jdbcType=BIGINT}, EQUIPMENT_NO = #{equipmentNo,jdbcType=BIGINT}, QUANTITY = #{quantity}, TON = #{ton,jdbcType=DOUBLE}, OPERATORS_ID = #{operatorsId,jdbcType=BIGINT}, OPERATORS_NAME = #{operatorsName,jdbcType=VARCHAR}, UPDATE_BY = #{loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{now}
WHERE id = #{id}

UPDATE T_YARD_TALLY_ITEM
CARGO_NAME = #{cargoName,jdbcType=VARCHAR}, CARGO_CODE = #{cargoCode,jdbcType=VARCHAR}, CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}, STOREHOUSE_ID = #{storehouseId,jdbcType=BIGINT}, STOREHOUSE_NAME = #{storehouseName,jdbcType=BIGINT}, QUANTITY = #{quantity}, TON = #{ton,jdbcType=DOUBLE}, LOCATION_ID = #{locationId,jdbcType=BIGINT}, LOCATION_NO = #{locationNo,jdbcType=VARCHAR}, STACK_POSITION_NAME = #{stackPositionName,jdbcType=VARCHAR}, STACK_POSITION_ID = #{stackPositionId,jdbcType=VARCHAR}, UPDATE_BY = #{loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{now}
WHERE id = #{id}

mapper.select:
SELECT A.CARGO_INFO_NO || '/' || A.CARGO_OWNER_NAME || '/' || A.CARGO_NAME "cargoInfoLabel", A.QUANTITY "cargoQuantity", A.TON "cargoTon", A.ID "cargoInfoId" FROM T_BUS_CARGO_INFO A, T_BUS_TRUST_CARGO AA WHERE AA.TRUST_ID = #{trustId} AND A.ID = AA.CARGO_INFO_ID
AND A.CARGO_INFO_NO like #{cargoInfoNoLike}
ORDER BY A.CARGO_INFO_NO

SELECT T2.CARGO_INFO_ID "cargoInfoId", SUM (T2.QUANTITY) "quantity", SUM (T2.TON) "ton", COUNT (DISTINCT T1. ID) "cars" FROM T_YARD_TALLY T1, T_YARD_TALLY_ITEM T2, T_PRD_WORK_PLAN T4, T_BUS_CARGO_INFO T3 WHERE T1. ID = T2.TALLY_ID AND T1.DEL_FLAG = 0 AND T1.PLAN_ID = T4. ID AND T3.ID = T2.CARGO_INFO_ID AND T2.CARGO_INFO_ID = #{cargoInfoId}
AND T4.WORK_DATE = TO_DATE(#{workDate},'YYYY-MM-DD')
AND T4.CLASS_CODE = #{classCode}
AND T1.PROCESS_CODE IN
#{item}
GROUP BY T2.CARGO_INFO_ID

