tallying_status='9', weight_status = '3', mark = '3'
WHERE platenumber = #{truckPlate,jdbcType=VARCHAR} and weightCode = #{unionNo,jdbcType=VARCHAR}

mapper.insert:
UPDATE T_BUS_RESERVATION_CONFIRM SET STATUS = #{confirmStatus, jdbcType=VARCHAR}, UPDATE_BY = #{loginUserId, jdbcType=BIGINT},
QUANTITY = #{quantity, jdbcType=BIGINT},
UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{now, jdbcType=TIMESTAMP}, CONFIRM_END_TIME = #{now, jdbcType=TIMESTAMP} WHERE STATUS = 1 AND TRUCK_NO = #{macName} AND PLAN_ID = #{planId, jdbcType=BIGINT}

mapper.select:
SELECT
    MAC_NO AS "doorName",
    STORAGE_YARD_NM AS "storageYardNm"
FROM T_BUS_RESERVATION_CONFIRM
WHERE TRUCK_NO = #{macName,jdbcType=VARCHAR}
  AND PLAN_ID =  #{planId,jdbcType=VARCHAR}
  AND CREATE_TIME = (
    SELECT MAX(CREATE_TIME)
    FROM T_BUS_RESERVATION_CONFIRM
    WHERE TRUCK_NO = #{macName,jdbcType=VARCHAR}
      AND PLAN_ID = #{planId,jdbcType=VARCHAR}
)
